mapper.select:
SELECT SP.IDX AS IDX ,SP.POLICY_NAME AS NAME ,SP.COMMENT AS COMMENT ,DU.datatype_label AS TYPE ,DU.datatype_label AS TYPE1 ,DU.DATATYPE_ID AS DATATYPE_ID ,DU.STD_ID AS STD_ID ,SP.SCHEDULE_PAUSE_DAYS AS PAUSE_DAYS ,SP.OPEN AS OPEN ,SP.USER_NO AS USER_NO ,SP.CYCLE AS CYCLE ,SP.OPEN AS OPEN ,SP.SCHEDULE_CPU AS CPU ,SP.SCHEDULE_MEMORY AS MEMORY ,SP.SCHEDULE_TRACE AS TRACE ,IFNULL(SP.ACTION, 0) AS ACTION ,DATE_FORMAT(SP.START_DTM, '%Y-%m-%d %H:%i') AS START_DTM ,SCHEDULE_PAUSE_FROM AS PAUSE_FROM ,SCHEDULE_PAUSE_FROM_MINU AS PAUSE_FROM_MINU ,SCHEDULE_PAUSE_TO AS PAUSE_TO ,SCHEDULE_PAUSE_TO_MINU AS PAUSE_TO_MINU ,rrn AS RRN ,rrn_cnt AS RRN_CNT ,rrn_dup AS RRN_DUP ,foreigner AS FOREIGNER ,foreigner_cnt AS FOREIGNER_CNT ,foreigner_dup AS FOREIGNER_DUP ,driver AS DRIVER ,driver_cnt AS DRIVER_CNT ,driver_dup AS DRIVER_DUP ,passport AS PASSPORT ,passport_cnt AS PASSPORT_CNT ,passport_dup AS PASSPORT_DUP ,ACCOUNT AS ACCOUNT ,account_cnt AS ACCOUNT_CNT ,account_dup AS ACCOUNT_DUP ,card AS CARD ,card_cnt AS CARD_CNT ,card_dup AS CARD_DUP ,phone AS PHONE ,phone_cnt AS PHONE_CNT ,phone_dup AS PHONE_DUP ,mobile_phone AS MOBILE_PHONE ,mobile_phone_cnt AS MOBILE_PHONE_CNT ,mobile_phone_dup AS MOBILE_PHONE_DUP ,local_phone AS LOCAL_PHONE ,local_phone_cnt AS LOCAL_PHONE_CNT ,local_phone_dup AS LOCAL_PHONE_DUP ,email AS EMAIL ,email_cnt AS EMAIL_CNT ,email_dup AS EMAIL_DUP ,policy_type AS POLICY_TYPE ,DU.recent AS RECENT ,CONCAT('[',GROUP_CONCAT(JSON_OBJECT( 'datatype_id', DU.DATATYPE_ID, 'ap_no', DU.AP_NO), ''),']') AS DATATYPES FROM PI_DATATYPES_USER DU,PI_SCAN_POLICY SP LEFT OUTER JOIN pi_scan_policy_server SPS ON SP.IDX = SPS.POLICY_ID
WHERE 1=1 AND DU.ENABLE = 1 AND SP.STD_ID = DU.STD_ID AND SP.ENABLE = 1 AND DU.ENABLE = 1
AND SP.POLICY_NAME like concat('%', #{name}, '%')
AND SP.IDX = #{policyid}
GROUP BY SP.IDX ORDER BY SP.OPEN, SP.IDX DESC;

