UPDATE PI_SCAN_POLICY SET OPEN = 0;
INSERT INTO PI_SCAN_POLICY (POLICY_NAME, DATATYPE_ID, STD_ID, USER_NO, SCHEDULE_CPU, SCHEDULE_MEMORY, SCHEDULE_TRACE, OPEN, CYCLE, REGDATE) VALUES (#{policy_name}, #{datatype_id}, #{std_id}, #{user_no}, #{cpu}, #{memory}, #{trace}, #{open}, #{cycle}, NOW())
SELECT LAST_INSERT_ID() AS idx

DELETE FROM PI_SCAN_POLICY_SERVER  
