mapper.select:
SELECT ST.TARGET_ID, ST.AP_NO, T.NAME AS FULL_NAME, SUBSTRING_INDEX(T.NAME, '.', 1) AS HOST_NAME, SUBSTRING_INDEX(SUBSTRING_INDEX(T.NAME, '.', -2), '.', 1) AS NAME, SUBSTRING_INDEX(T.NAME, '.', -1) AS SERIAL, T.PLATFORM, ST.RECON_SCHEDULE_ID, ST.POLICY_ID, (SELECT P.policy_name FROM pi_scan_policy P WHERE ST.POLICY_ID = P.idx) AS POLICY_NAME, ST.DATATYPE_ID, DU.DATATYPE_LABEL, DU.ENABLE, S.SCHEDULE_STATUS, DATE_FORMAT(ST.REGDATE, '%Y-%m-%d %H:%i:%S') AS REGDATE FROM pi_schedule_targets ST LEFT OUTER JOIN pi_datatypes_user DU ON ST.DATATYPE_ID = DU.DATATYPE_ID LEFT OUTER JOIN pi_locations L ON L.TARGET_ID = ST.TARGET_ID AND ST.LOCATION_ID = L.LOCATION_ID , pi_targets T, pi_schedules S WHERE 1 = 1 AND ST.RECON_SCHEDULE_ID = S.SCHEDULE_ID AND ST.AP_NO = S.AP_NO AND ST.TARGET_ID = T.TARGET_ID AND ST.AP_NO = T.AP_NO AND ST.SCHEDULE_GROUP_ID = #{group_id}
AND S.SCHEDULE_STATUS IN (
#{item}
)
GROUP BY T.TARGET_ID, T.AP_NO, ST.RECON_SCHEDULE_ID ORDER BY T.NAME

SELECT DU.AP_NO, DU.DATATYPE_ID 
FROM pi_datatypes_user DU
WHERE DU.STD_ID = #{std_id}

